import sys

class Solution:
    def solve(self, boards: list[int], k: int) -> int:
        # binary search on answer
        lo = max(boards)
        hi = sum(boards)
        def can(limit: int) -> bool:
            painters = 1
            cur = 0
            for w in boards:
                if cur + w <= limit:
                    cur += w
                else:
                    painters += 1
                    cur = w
                    if painters > k:
                        return False
            return True
        while lo < hi:
            mid = (lo + hi) // 2
            if can(mid):
                hi = mid
            else:
                lo = mid + 1
        return lo

