#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int solve(vector<int>& boards, int k) {
        long long lo = *max_element(boards.begin(), boards.end());
        long long hi = accumulate(boards.begin(), boards.end(), 0LL);
        auto can = [&](long long limit) {
            int painters = 1;
            long long cur = 0;
            for (int w : boards) {
                if (cur + w <= limit) {
                    cur += w;
                } else {
                    ++painters;
                    cur = w;
                    if (painters > k) return false;
                }
            }
            return true;
        };
        while (lo < hi) {
            long long mid = (lo + hi) / 2;
            if (can(mid)) hi = mid; else lo = mid + 1;
        }
        return (int)lo;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> boards(n);
    for (int i = 0; i < n; ++i) cin >> boards[i];
    int k;
    if (!(cin >> k)) return 0;
    Solution sol;
    int ans = sol.solve(boards, k);
    cout << ans << "\n";
    return 0;
}
